+#[inline]
+fn registration_interest(read_waiter: bool, write_waiter: bool, fallback: Interest) -> Interest {
+    let mut interest = Interest::empty();
+    if read_waiter {
+        interest |= Interest::READABLE;
+    }
+    if write_waiter {
+        interest |= Interest::WRITABLE;
+    }
+    if interest.is_empty() {
+        fallback
+    } else {
+        interest
+    }
+}
